use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct CacheEntry {
    value: String,
    expiry_time: u64,
}

impl CacheEntry {
    fn new(value: String, expiry: u64) -> Self {
        CacheEntry { value, expiry_time: expiry }
    }
}

type SharedCache = Arc<Mutex<HashMap<String, CacheEntry>>>;

fn process_get(cache: &SharedCache, key: &str) -> Option<String> {
    let map = cache.lock().unwrap();
    if let Some(entry) = map.get(key) {
        if entry.expiry_time > 0 {
            return Some(format!("Found value for {}: {}", key, entry.value));
        }
    }
    None
}

fn main() {
    let cache: SharedCache = Arc::new(Mutex::new(HashMap::new()));
    {
        let mut map_write = cache.lock().unwrap();
        map_write.insert("user:1".to_string(), CacheEntry::new("Alice Data".to_string(), 1678886400));
    }

    let cache_clone = Arc::clone(&cache);
    let handle = std::thread::spawn(move || {
        process_get(&cache_clone, "user:1");
    });

    std::thread::sleep(std::time::Duration::from_millis(50));

    match process_get(&cache, "user:1") {
        Some(msg) => println!("Main thread successfully read: {}", msg),
        None => println!("Failed to read from main thread.")
    }

    handle.join().unwrap();
}

use std::sync::{mpsc, Arc};

struct MessageProcessor {
    id: u32,
}
impl MessageProcessor {
    fn process_message(&self, data: String) -> Result<String, &'static str> {
        if data.is_empty() {
            return Err("Cannot process empty message.");
        }
        if data.contains("CRASH") {
            return Err("Simulated critical failure during processing.");
        }
        Ok(format!("Processor {} successfully handled: {}", self.id, data.to_uppercase()))
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx, rx) = mpsc::channel::<String>();
    let processor1 = Arc::new(MessageProcessor { id: 1 });
    let processor2 = Arc::new(MessageProcessor { id: 2 });

    let mut handles = Vec::new();
    for i in 0..3 {
        if i == 0 {
            let p_clone = processor1.clone();
            let tx_clone = tx.clone();
            handles.push(std::thread::spawn(move || {
                let result = p_clone.process_message("Hello world".to_string());
                match result {
                    Ok(msg) => tx_clone.send(format!("[Success]: {}", msg)).unwrap(),
                    Err(e) => tx_clone.send(format!("[Error]: {}", e)).unwrap(),
                }
            }));
        } else if i == 1 {
            let p_clone = processor2.clone();
            let tx_clone = tx.clone();
            handles.push(std::thread::spawn(move || {
                let result = p_clone.process_message("CRASH".to_string());
                match result {
                    Ok(msg) => tx_clone.send(format!("[Success]: {}", msg)).unwrap(),
                    Err(e) => tx_clone.send(format!("[Error]: {}", e)).unwrap(),
                }
            }));
        } else {
            let p_clone = processor1.clone();
            let tx_clone = tx.clone();
            handles.push(std::thread::spawn(move || {
                let result = p_clone.process_message("Empty".to_string());
                match result {
                    Ok(msg) => tx_clone.send(format!("[Success]: {}", msg)).unwrap(),
                    Err(e) => tx_clone.send(format!("[Error]: {}", e)).unwrap(),
                }
            }));
        }
    }

    for handle in handles {
        handle.join().expect("Thread panicked during join");
    }

    drop(tx);

    let mut results = Vec::new();
    while let Ok(message) = rx.recv() {
        results.push(message);
    }

    for result_msg in results {
        println!("{}", result_msg);
    }

    Ok(())
}

use std::thread;
use std::sync::mpsc;
use std::error::Error;

struct ParseResult {
    ok: bool,
    message: String,
}

fn worker_task(input: i32) -> Result<ParseResult, String> {
    if input > 0 {
        Ok(ParseResult { ok: true, message: format!("Successfully parsed value {}", input) })
    } else {
        Err(format!("Parsing failed for negative input {}", input))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let (tx, rx) = mpsc::channel::<Result<ParseResult, String>>();

    let handles: Vec<_> = (1..=3)
        .map(|i| { 
            let tx_clone = tx.clone();
            thread::spawn(move || {
                match worker_task(i * -1) {
                    Ok(result) => tx_clone.send(Ok(result)).unwrap(),
                    Err(e) => tx_clone.send(Err(e)).unwrap(),
                }
            })
        }) 
        .collect();

    let mut collected_errors = Vec::new();
    let mut successful_results = Vec::new();

    for _ in 1..=3 {
        match rx.recv() {
            Ok(result) => match result {
                Ok(res) => successful_results.push(res),
                Err(e) => collected_errors.push(e),
            },
            Err(_) => break,
        }
    }

    if !collected_errors.is_empty() {
        println!("Encountered {} critical errors across threads:n", collected_errors.len());
        for error in collected_errors {
            println!("  -> {}", error);
        }
        return Err(Box::new(std::io::Error::new(std::io::ErrorKind::Other, "One or more threads failed.")));
    }

    println!("All tasks completed successfully. Results:n");
    for result in successful_results {
        println!("  {}", &result.message);
    }

    Ok(())
}

use std::thread;
use std::error::Error;
use std::fmt;

struct MessageProcessingError {
    source: Box<dyn Error + Send + Sync>,
}

impl fmt::Display for MessageProcessingError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Message processing failed: {}", self.source)
    }
}

impl From<Box<dyn Error + Send + Sync>> for MessageProcessingError {
    fn from(source: Box<dyn Error + Send + Sync>) -> Self {
        Self { source }
    }
}

fn process_single_message(message_id: u32) -> Result<(), Box<dyn Error + Send + Sync>> {
    if message_id % 5 == 0 {
        return Err(format!("Failed to serialize message ID {}", message_id).into());
    }
    println!("Successfully processed message {}", message_id);
    Ok(())
}

fn main() -> Result<(), Box<dyn Error + Send + Sync>> {
    let message_ids: Vec<u32> = (1..=10).collect();
    let mut handles = vec![];

    for id in message_ids {
        let handle_id = id;
        let handle = thread::spawn(move || -> Result<(), Box<dyn Error + Send + Sync>> {
            process_single_message(handle_id)
        });
        handles.push(handle);
    }

    for handle in handles {
        match handle.join() {
            Ok(result) => match result {
                Ok(()) => {}, 
                Err(e) => println!("Caught expected error for a thread: {}", e),
            },
            Err(_) => println!("Thread panicked unexpectedly.")
        }
    }

    Ok(())
}

use std::thread;
use std::sync::mpsc;
use std::error::Error;

struct JobResult {
    success: bool,
    message: String,
}

impl Clone for JobResult {
    fn clone(&self) -> Self {
        JobResult {
            success: self.success,
            message: self.message.clone(),
        }
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let (tx, rx) = mpsc::channel::<JobResult>();

    let tx1 = tx.clone();
    let job1_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(50));
        tx1.send(JobResult { success: true, message: "Map phase completed for key A".to_string() }).ok();
    });

    let tx2 = tx.clone();
    let job2_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(100));
        tx2.send(JobResult { success: false, message: "Worker failed due to invalid input format".to_string() }).ok();
    });

    let tx3 = tx.clone();
    let job3_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(20));
        tx3.send(JobResult { success: true, message: "Reduce phase finished for key B".to_string() }).ok();
    });

    drop(tx);

    let mut results = Vec::new();
    let mut overall_success = true;

    while let Ok(result) = rx.recv() {
        results.push(result.clone());
        if !result.success {
            overall_success = false;
        }
    }

    job1_handle.join().ok();
    job2_handle.join().ok();
    job3_handle.join().ok();

    if overall_success {
        println!("All jobs completed successfully.");
    } else {
        eprintln!("Job execution failed. Found {} errors.", results.iter().filter(|r| !r.success).count());
        for result in results {
            if !result.success {
                println!("--> Error: {}", result.message);
            }
        }
        return Err(Box::new(std::io::Error::new(std::io::ErrorKind::Other, "One or more jobs failed")));
    }

    Ok(())
}
